import static org.junit.jupiter.api.Assertions.assertEquals;

import com.google.gson.internal.bind.DefaultDateTypeAdapter;
import java.lang.reflect.Field;
import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class DefaultDateTypeAdapterTest {

  private DefaultDateTypeAdapter<Date> adapter;

  @BeforeEach
  void setUp() throws Exception {
    // Use reflection to invoke private constructor DefaultDateTypeAdapter(DateType<T>, String)
    // Since DateType is not provided, use a dummy stub for it
    Class<?> dateTypeClass = Class.forName("com.google.gson.internal.bind.DefaultDateTypeAdapter$DateType");
    Object dummyDateType = java.lang.reflect.Proxy.newProxyInstance(
        dateTypeClass.getClassLoader(),
        new Class<?>[]{dateTypeClass},
        (proxy, method, args) -> null);

    var ctor = DefaultDateTypeAdapter.class.getDeclaredConstructor(dateTypeClass, String.class);
    ctor.setAccessible(true);
    adapter = (DefaultDateTypeAdapter<Date>) ctor.newInstance(dummyDateType, "yyyy-MM-dd");

    // Clear and set dateFormats to contain a SimpleDateFormat with known pattern
    Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    List<DateFormat> dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);
    dateFormats.clear();
    dateFormats.add(new SimpleDateFormat("yyyy-MM-dd"));
  }

  @Test
  void testToString_withSimpleDateFormat() {
    String expected = "DefaultDateTypeAdapter(yyyy-MM-dd)";
    assertEquals(expected, adapter.toString());
  }

  @Test
  void testToString_withNonSimpleDateFormat() throws Exception {
    // Replace dateFormats with a DateFormat subclass not SimpleDateFormat
    Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    List<DateFormat> dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);
    dateFormats.clear();

    DateFormat customDateFormat = new DateFormat() {
      @Override
      public StringBuffer format(Date date, StringBuffer toAppendTo, java.text.FieldPosition fieldPosition) {
        return toAppendTo.append("custom");
      }

      @Override
      public Date parse(String source, ParsePosition pos) {
        return null;
      }

      @Override
      public String getClass().getSimpleName() {
        return "CustomDateFormat";
      }
    };
    dateFormats.add(customDateFormat);

    String expected = "DefaultDateTypeAdapter(CustomDateFormat)";
    assertEquals(expected, adapter.toString());
  }
}
